// Normalize an incoming alert into a stable incident object.
const body = $input.first().json.body ?? {};

const service = String(body.service ?? 'unknown').trim().toLowerCase();
const level   = String(body.level   ?? 'ERROR').trim().toUpperCase();
const message = String(body.message ?? '').trim();

// A signature is the message with volatile bits (numbers, hex ids, timestamps)
// stripped, so "timeout after 30000ms" and "timeout after 12ms" collapse to one.
const signature = message
  .replace(/\b[0-9a-f]{8,}\b/gi, 'ID')   // hex ids / trace ids
  .replace(/\d+/g, 'N')                  // any run of digits
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 120);

const incident = {
  service,
  level,
  message,
  signature,
  fingerprint: `${service}:${signature}`,
  received_at: new Date().toISOString(),
};

return [{ json: incident }];
